sp_widget.client_script:
api.controller=function() {
    var c = this;

    var today = new Date();
    var curHr = today.getHours();
    var greeting;
    if (curHr < 12) greeting = 'Good morning';
    else if (curHr < 18) greeting = 'Good afternoon';
    else greeting = 'Good evening';

    c.data.greeting = greeting;

}

sp_widget.css:
/* =============================================
   Pulse Pharmacy Hero Section - Split Screen (معدل)
============================================== */

/* حاوية البانر الرئيسية */
.hero-split-screen {
    display: flex;
    justify-content: space-between;
    align-items: center; /* تغيير من 'stretch' إلى 'center' لتجنب التمدد الزائد */
    background: linear-gradient(135deg, #FFFFFF 0%, #F8FAFC 100%);
    border-radius: 20px;
    margin: 20px 0;
    overflow: hidden;
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.05);
    gap: 20px; /* مسافة بين العمودين */
}

/* قسم النصوص */
.hero-content {
    flex: 1.2; /* إعطاء مساحة أكبر قليلاً للنص */
    padding: 40px 40px;
    display: flex;
    flex-direction: column;
    justify-content: center;
}

/* شارة الترحيب */
.welcome-badge {
    background-color: #E60000;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 6px 16px;
    border-radius: 40px;
    color: white;
    font-weight: 500;
    margin-bottom: 20px;
    width: fit-content;
    font-size: 14px;
}

/* العنوان الرئيسي */
.hero-title {
    font-size: 42px;
    font-weight: 800;
    line-height: 1.2;
    color: #0F172A;
    margin-bottom: 16px;
}

/* النص الوصفي */
.hero-description {
    font-size: 16px;
    color: #475569;
    
    max-width: 90%;
    line-height: 1.5;
}


/* قسم الصورة */
.hero-image {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    border-radius: 0 20px 20px 0;
    min-height: auto; /* إزالة الارتفاع الثابت */
}
.hero-image img {
    width: 100%;
    height: auto;
    object-fit: contain; /* تغيير من cover إلى contain لعدم قص الصورة */
    display: block;
    min-height: 500px; /* تحديد أقصى ارتفاع للصورة */
}



/* استجابة للشاشات الصغيرة */
@media (max-width: 992px) {
    .hero-split-screen {
        flex-direction: column;
        text-align: center;
    }
    .hero-content {
        order: 2;
        padding: 30px 20px;
    }
    .hero-image {
        order: 1;
        width: 100%;
        border-radius: 20px 20px 0 0;
        min-height: auto;
    }
    .hero-image img {
        max-height: 300px;
    }
    .hero-description {
        max-width: 100%;
    }
    .welcome-badge {
        margin-left: auto;
        margin-right: auto;
    }
}

























/* إصلاح المسافات في شريط البحث homepage-search */
#homepage-search h2,
#homepage-search .sp-search-heading {
    display: none !important;
    margin: 0 !important;
    padding: 0 !important;
    height: 0 !important;
}

#homepage-search .wrapper-xl {
    padding: 0 !important;
    margin: 0 !important;
}

#homepage-search .input-group {
    margin-bottom: 0 !important;
}

/* ضبط شكل زر البحث والأيقونة */
#homepage-search .input-group-btn button {
    background-color: #E60000 !important;
    border: none !important;
    color: white !important;
    border-radius: 0 60px 60px 0 !important;
    padding: 0 25px !important;
}

#homepage-search .input-group-btn button i {
    color: white !important;
}

/* إذا ظهرت أي مسافات إضافية من عناصر أخرى */
#homepage-search form {
    margin: 0 !important;
}

/* تقليل المسافات العامة للـ Hero Section */
.hero-split-screen {
    align-items: center;
}
.hero-content {
    padding: 30px 40px !important;
}
.search-container {
    margin-top: 10px !important;
}

